import React, { useState } from "react";
import "./App.css";

function App() {
  const [patientId, setPatientId] = useState("");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");

  const fetchProfile = async () => {
    try {
      setError("");
      const response = await fetch(
        `http://127.0.0.1:5000/emergency/${patientId}`
      );

      const result = await response.json();

      if (!response.ok) {
        setError(result.message || "Error fetching data");
        setData(null);
      } else {
        setData(result);
      }
    } catch (err) {
      setError("Server not reachable");
      setData(null);
    }
  };

  return (
    <div className="container">
      <h1>Emergency Profile Viewer</h1>

      <div className="input-section">
        <input
          type="text"
          placeholder="Enter Patient ID"
          value={patientId}
          onChange={(e) => setPatientId(e.target.value)}
        />
        <button onClick={fetchProfile}>Search</button>
      </div>

      {error && <p className="error">{error}</p>}

      {data && (
        <div className="card">
          <p><strong>Name:</strong> {data.name}</p>
          <p><strong>Address:</strong> {data.address}</p>
          <p><strong>Gender:</strong> {data.gender}</p>
          <p><strong>Contact Name:</strong> {data.contact_name}</p>
          <p><strong>Contact Phone:</strong> {data.contact_phone}</p>
          <p><strong>Chronic Conditions:</strong> {data.chronic_conditions}</p>
          <p><strong>Blood Group:</strong> {data.blood_group}</p>
          <p><strong>Allergies:</strong> {data.allergies}</p>
        </div>
      )}
    </div>
  );
}

export default App;
